INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 2, 'Wawasan', 'Posisi duduk badan pengemudi yang baik saat mengendarai mobil   untuk menghindari kelelahan adalah mengambil sikap duduk yang nyaman. Posisi duduk badan pengemudi waktu mengendarai mobil adalah penting untuk menghindari kelelahan, yang baik adalah?', 'https://e-avismedia.korlantas.polri.go.id/video360/uUMmg3ukBj486QZazpLb.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 2, 'Wawasan', 'Bila merasa lelah atau mengantuk sewaktu mengendarai kendaraan,   pengendara harus beristirahat dahulu. Bila merasa lelah atau mengantuk, sewaktu mengendarai kendaraan, pengemudi harus?', 'https://e-avismedia.korlantas.polri.go.id/video360/7EozQs2730ti5bSaYVoI.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 2, 'Wawasan', 'Untuk mengemudikan sebuah mobil Colt L 300 pribadi dengan model mini bus dan terdiri dari 4 baris tempat duduk untuk 10 penumpang dan 1 pengemudi, dengan berat kurang dari 3.500 kg, maka pengemudinya harus memiliki   SIM A  sebagai persyaratan pengemudi.  Untuk mengemudikan sebuah mobil Colt L 300 pribadi dengan model mini bis dan terdiri dari 4 baris tempat duduk untuk 10 penumpang dan 1 pengemudi, maka pengemudinya harus memiliki SIM?', 'https://e-avismedia.korlantas.polri.go.id/video360/wOFbFrPV5zR9pVexAlHC.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 2, 'Pengetahuan', 'Rambu disamping   merupakan rambu larangan kendaraan untuk berbalik arah.   Sehingga pengendara tidak diperbolehkan berbalik arah pada U-turn yang terdapat rambu tersebut.  Apa arti rambu ini?', 'https://e-avismedia.korlantas.polri.go.id/video360/76xnc1mmXj6sRpPee0mi.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 2, 'Pengetahuan', 'Berdasarkan Peraturan Kepolisian Nomor 5 tahun 2021 tentang Penerbitan dan Penandaan SIM,   penggunaan SIM A ditujukan untuk mengemudikan kendaraan bermotor dengan jumlah beratnya tidak melebihi 3.500 Kg berupa mobil penumpang dan mobil barang perseorangan. Sebagai pemilik SIM A, Anda dapat mengemudikan?', 'https://e-avismedia.korlantas.polri.go.id/video360/suzNB9qpJ1QJLEUHY1G3.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 2, 'Pengetahuan', 'Berdasarkan Peraturan Kepolisian Nomor 7 tahun 2021 tentang Registrasi dan  Identifikasi Kendaraan Bermotor, bahwa STNK  merupakan dokumen sebagai bukti legitimasi pengoperasian Ranmor yang berbentuk surat atau bentuk lain yang diterbitkan Polri yang berisi identitas pemilik, identitas Ranmor dan masa berlaku termasuk pengesahannya. Sehingga,   orang yang bukan pemilik kendaraan tersebut diperbolehkan menggunakan STNK tersebut asalkan menggunakan kendaraan yang sesuai dengan catatan dalam STNK. Dapatkah STNK digunakan oleh yang bukan pemilik kendaraan yang bersangkutan?', 'https://e-avismedia.korlantas.polri.go.id/video360/ScskVLRDMfDDAcZ2A69L.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 2, 'Pengetahuan', 'Berdasarkan Peraturan Kepolisian Nomor 5 tahun 2021 tentang Penerbitan dan Penandaan SIM,   syarat permohonan usia SIM A adalah paling rendah 17 tahun. Untuk mendapatkan SIM setiap orang harus memenuhi Persyaratan Usia, Administratif, Kesehatan dan Lulus Ujian. Adapun Syarat usia Pemohon SIM A adalah?', 'https://e-avismedia.korlantas.polri.go.id/video360/8E3EcWCZc804NypxJI4P.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 2, 'Pengetahuan', 'Berdasarkan Peraturan Kepolisian Nomor 5 tahun 2021 tentang Penerbitan dan Penandaan SIM,   setiap pemohon SIM A wajib memenuhi persyaratan usia, administrasi, kesehatan dan lulus ujian. Untuk mendapatkan SIM A setiap orang harus memenuhi Persyaratan usia, administrasi, kesehatan, dan lulus ujian?', 'https://e-avismedia.korlantas.polri.go.id/video360/J4Db2KZb8MOZTZRwA44V.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
