INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 3, 'Wawasan', 'Lampu lalu lintas menyala kuning berkedip- kedip,   yang harus dilakukan oleh pengemudi sedan adalah berjalan terus tetapi hati-hati dan jika perlu berhenti di garis berhenti untuk mengamati lalu lintas yang memotong sampai keadaan aman. Lampu lalu lintas menyala kuning berkedip- kedip. Apa yang harus dilakukan oleh pengemudi sedan itu?', 'https://e-avismedia.korlantas.polri.go.id/video360/MFdNwtR5mYe64KYkDLG0.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 3, 'Wawasan', 'Situasi pada video tersebut, sebagai pengendara roda 4 (Empat),   yang harus di lakukan adalah melakukan pengereman kemudian menghindar. Jika Anda sebagai seorang pengemudi Roda 4, apa yg Anda lakukan?', 'https://e-avismedia.korlantas.polri.go.id/video360/0s3IexKm3tOPzUDPWGto.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
