INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 3, 'Pengetahuan', 'Jalan arteri merupakan   jalan umum yang berfungsi melayani angkutan utama untuk perjalanan jarak jauh, dengan kecepatan sekitar >60km/jam. Lebar badan jalannya mencapai >8m. Kapasitas jenis jalan ini cenderung lebih besar dari volume lalu lintas rata-rata. Jalan arteri tidak boleh terganggu oleh kegiatan lokal. Jalan arteri merupakan jalan yang berfungsi  untuk?', 'https://e-avismedia.korlantas.polri.go.id/video360/3g9HAyxLamD2ukXL0v9M.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 3, 'Pengetahuan', 'Secara Psikologis   peserta uji SIM harus berusia minimal 17 tahun   karena pada usia tersebut seseorang dianggap mampu untuk fokus dan mengambil keputusan yang tepat, serta dianggap mampu untuk mengambil merespon serta bertindak secara antisipatif terhadap keadaan tertentu saat diperlukan. Mengapa syarat minimum permohonan SIM A adalah pemohon harus berusia minimal 17  tahun?', 'https://e-avismedia.korlantas.polri.go.id/video360/1QWTAkD7hM6JTiMhLodK.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
