INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM A', 3, 'Pengetahuan', 'APAR merupakan alat yang digunakan untuk memadamkan api atau mengendalikan kebakaran kecil . Alat Pemadam Api Ringan (APAR) pada umumnya berbentuk tabung yang diisikan dengan bahan pemadam api yang bertekanan tinggi.  Fungsi Alat Pemadam Api Ringan (APAR) pada mobil adalah untuk memadamkan api berskala kecil apabila terjadi kebarakan mendadak  pada mobil. Benar atau salah?', 'https://e-avismedia.korlantas.polri.go.id/video360/Ix71PqpKaPTtbo778HhD.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
