INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM C', 3, 'Pengetahuan', 'SATPAS (Satuan Penyelenggara Administrasi SIM) merupakan   unsur pelaksana Polri dibidang lalu lintas yang berada di lingkungan kantor Kepolisian setempat yang bertanggungjawab mengenai SIM pada pengemudi. Tempat untuk mengajukan permohonan pembuatan SIM adalah?', 'https://e-avismedia.korlantas.polri.go.id/video360/iCKGgF0ZJ96FSbbcZAxE.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
