INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM C', 4, 'Pengetahuan', 'Berdasarkan Peraturan Kepolisian nomor 5 tahun 2021,   SIM adalah bukti legitimasi kompetensi pengemudi sesuai jenis dan golongan SIM yang dimilikinya setelah memenuhi persyaratan administrasi, usia, kesehatan jasmani maupun rohani, serta dinyatakan lulus melalui proses pengujian. Apakah fungsi dari SIM bagi pengendara kendaraan bermotor?', 'https://e-avismedia.korlantas.polri.go.id/video360/5OoGX5BL3FZtbn8Yhsfy.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
INSERT INTO questions (exam_type, module_number, material_category, question_text, media_url, media_type, options) VALUES ('SIM C', 4, 'Pengetahuan', 'Berdasarkan Peraturan Kepolisian nomor 5 tahun 2021,   SIM tidak diperbolehkan untuk dipindahtangkan karena hanya dapat digunakan oleh individu yang tercatat identitasnya pada SIM tersebut. Apakah SIM dapat dipindah tangankan dalam penggunaan kendaraan bermotor di jalan raya?', 'https://e-avismedia.korlantas.polri.go.id/video360/vJmRS5rKDw0rhOSVn8my.mp4', 'video', '[{"id":"A","text":"","isCorrect":true},{"id":"B","text":"","isCorrect":false},{"id":"C","text":"","isCorrect":false}]'::jsonb);
